/**
 * Minimal ANSI escape code parser for log viewer output.
 *
 * Handles:
 *   - Colors 30-37 (standard foreground)
 *   - Colors 90-97 (bright/high-intensity foreground)
 *   - Bold (1)
 *   - Reset (0)
 *
 * Returns an array of text segments, each with an optional DDS token class.
 * @internal
 */
type AnsiSegment = {
    text: string;
    className?: string;
};
/**
 * Parse a string containing ANSI escape sequences into styled segments.
 * Returns segments with `text` content and optional Tailwind `className`.
 */
declare function parseAnsi(input: string): AnsiSegment[];

export { type AnsiSegment, parseAnsi };
